                    <div class="card-body">
                        <h6 class="card-title">Theme</h6>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="theme-@theme" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                @* Font Size *@
                <div class="card mb-3">
                    <div class="card-body">
                        <h6 class="card-title">Font Size</h6>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="fs-@size" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>
                </div>

                @* Language *@
                <div class="card mb-3">
                    <div class="card-body">
                        <h6 class="card-title">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in Languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                @* Compact Mode *@
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync">Save</button>
            </div>

            @* Live Preview *@
            <div class="col-md-6">
                <div class="preview-area @GetPreviewThemeClass()" style="font-size: @GetPreviewFontSize();">
                    <h6 class="preview-title">Live Preview</h6>
                    <div class="preview-content @(_compactMode ? "compact" : "")">
                        <div class="preview-header">Settings Dashboard</div>
                        <p class="preview-text">
                            This is how your content will look with the selected settings.
                        </p>
                        <div class="preview-card">
                            <strong>Sample Card</strong>
                            <p class="mb-0">Theme: @_theme · Font: @_fontSize · Lang: @_language</p>
                        </div>
                        <div class="preview-nav">
                            <span class="preview-nav-item active">Home</span>
                            <span class="preview-nav-item">Profile</span>
                            <span class="preview-nav-item">Settings</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private string? _message;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
    }

    private string GetPreviewThemeClass() => _theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string GetPreviewFontSize() => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };
}
