    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    height: 100%;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.nav-item {
    list-style: none;
}

.nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    width: 100%;
    padding: 0.75rem 1.25rem;
    border: none;
    background: none;
    color: #495057;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    text-align: left;
}

.nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.nav-link.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.nav-icon {
    font-size: 1.1rem;
}

