@using sv_22177a2d18414d108fc001a28b9eaaf8.Services
@inject ISettingsService SettingsService

<div class="profile-section">
    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <h4>Profile</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                    <div class="mt-2">
                        <label class="form-label text-muted small">Avatar URL</label>
                        <input class="form-control form-control-sm" @bind="_avatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private string? _message;
    private UserProfile _savedProfile = default!;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _message = "Profile saved successfully!";
    }

    private void Discard()
    {
        ApplyProfile(_savedProfile);
        _message = null;
    }
}

