+
+.preview-title {
+    margin-bottom: 0.75rem;
+    padding-bottom: 0.5rem;
+    border-bottom: 1px solid currentColor;
+    opacity: 0.6;
+}
+
+.preview-light {
+    background: #ffffff;
+    color: #212529;
+    border-color: #dee2e6;
+}
+
+.preview-dark {
+    background: #1e1e2e;
+    color: #cdd6f4;
+    border-color: #45475a;
+}
+
+.preview-system {
+    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
+    color: #212529;
+}
+
+.preview-content.compact {
+    line-height: 1.2;
+}
+
+.preview-content.compact .preview-card {
+    padding: 0.5rem;
+}
+
+.preview-content.compact p {
+    margin-bottom: 0.25rem;
+}
+
+.preview-header {
+    font-weight: 600;
+    font-size: 1.1em;
+    margin-bottom: 0.5rem;
+}
+
+.preview-text {
+    opacity: 0.8;
+}
+
+.preview-card {
+    border: 1px solid currentColor;
+    border-radius: 0.375rem;
+    padding: 0.75rem;
+    margin-bottom: 0.75rem;
+    opacity: 0.9;
+}
+
+.preview-nav {
+    display: flex;
+    gap: 1rem;
+    padding-top: 0.5rem;
+    border-top: 1px solid currentColor;
+    opacity: 0.6;
+}
+
+.preview-nav-item {
+    cursor: default;
+    padding: 0.25rem 0;
+}
+
+.preview-nav-item.active {
+    font-weight: 600;
+    opacity: 1;
+    border-bottom: 2px solid currentColor;
+}
