arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionSelected="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 100px);
    margin: -1rem -1.5rem;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

